mapper.select:
SELECT id, animal_type, chemical_name, dosage,
       indicator_name, indicator_value, temperature, create_time
FROM dataset_raw
WHERE animal_type    = #{animalType}
  AND chemical_name  = #{chemicalName}
  AND indicator_name = #{indicatorName}
  AND temperature BETWEEN #{minTemp} AND #{maxTemp}
ORDER BY dosage ASC

mapper.insert:
