) VALUES (
    #{animalType}, #{chemicalName}, #{dosage}, #{indicatorName}, #{indicatorValue}, #{temperature}
)

mapper.update:
UPDATE dataset_raw
animal_type = #{animalType}, chemical_name = #{chemicalName}, dosage = #{dosage}, indicator_name = #{indicatorName}, indicator_value = #{indicatorValue}, temperature = #{temperature},
WHERE id = #{id}
